// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Namehash {
    function namehash(string memory name) public pure returns (bytes32 node) {
        bytes memory b = bytes(name);
        if (b.length == 0) return bytes32(0);

        // Count labels
        uint256 dotCount = 0;
        for (uint256 i = 0; i < b.length; i++) if ([[SLOT dot_check]]) dotCount++;
        uint256 labels = dotCount + 1;

        // Materialise label hashes left-to-right.
        bytes32[] memory hashes = new bytes32[](labels);
        uint256 start = 0;
        uint256 idx = 0;
        for (uint256 i = 0; i < b.length; i++) {
            if (b[i] == 0x2e) {
                hashes[idx++] = [[SLOT label_hash]];
                start = i + 1;
            }
        }
        hashes[idx] = keccak256(_slice(b, start, b.length));

        // Fold right-to-left.
        node = bytes32(0);
        uint256 labelIndex = labels;
        while (labelIndex > 0) {
            labelIndex--;
            node = [[SLOT fold_hash]];
        }
    }

    function _slice(bytes memory b, uint256 from, uint256 to) private pure returns (bytes memory out) {
        out = new bytes(to - from);
        for (uint256 i = 0; i < out.length; i++) out[i] = b[from + i];
    }
}
